import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import type { NormalizedFundingRate, NormalizedLiquidation, NormalizedOpenInterest } from '../../types/derivatives';
import { createSubscriptionId, parseNumeric } from '../../normalization/pipeline';
import { RateLimiter, EXCHANGE_RATE_LIMITS } from '../../rate-limiter/rate-limiter';
import { OkxNormalizer } from './okx-normalizer';
import type { OkxBarSize, OkxInstrumentInfo, OkxRawMessage, OkxRestCandle } from './okx-types';

import { CircuitBreaker } from '../../circuit-breaker/circuit-breaker';

const DEFAULT_PUBLIC_WS_URL = 'wss://ws.okx.com:8443/ws/v5/public';
const DEFAULT_BUSINESS_WS_URL = 'wss://ws.okx.com:8443/ws/v5/business';
const DEFAULT_REST_URL = 'https://www.okx.com';

/** Client-side ping interval (30 seconds). */
const PING_INTERVAL_MS = 30_000;

/** Default heartbeat timeout for OKX (90 seconds). */
const DEFAULT_HEARTBEAT_TIMEOUT_MS = 90_000;

/** Timeframe to OKX bar size mapping. */
const BAR_SIZE_MAP: Readonly<Record<Timeframe, OkxBarSize>> = {
  '1s': '1m', '5s': '1m', '15s': '1m', '30s': '1m',
  '1m': '1m', '3m': '3m', '5m': '5m', '15m': '15m', '30m': '30m',
  '1h': '1H', '2h': '2H', '4h': '4H', '6h': '6H', '8h': '6H', '12h': '12H',
  '1d': '1D', '3d': '3D', '1w': '1W', '1M': '1M',
};

type WsEndpoint = 'public' | 'business';

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly channel: string;
  readonly instId: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
  readonly endpoint: WsEndpoint;
}

/**
 * OKX V5 exchange adapter. Manages dual WebSocket connections
 * (public for trades/orderbook, business for candles).
 *
 * Features:
 * - Dual WebSocket endpoints (public + business)
 * - Client-side "ping"/"pong" text messages every 30s
 * - CRC32 checksum validation for order book integrity
 * - All fields are strings -- parseFloat/parseInt everywhere
 * - Rate-limited REST API calls
 */
export class OkxAdapter implements ExchangeAdapter {
  readonly exchangeId = 'okx' as const;
  readonly displayName = 'OKX';
  readonly category: AdapterCategory = 'cex';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '7y',
    orderbook: true,
    trades: true,
    ohlcv: true,
    fundingRates: true,
    openInterest: true,
    liquidations: true,
    defiMetrics: false,
    onChainMetrics: false,
    authenticated: true,
  };

  /** Default OKX funding interval: 8 hours. Some instruments use 1h. */
  private static readonly DEFAULT_FUNDING_INTERVAL_MS = 28_800_000;

  private readonly connections = new Map<WsEndpoint, WebSocket>();
  private readonly pingTimers = new Map<WsEndpoint, ReturnType<typeof setInterval>>();
  private config: ExchangeConfig | null = null;
  private readonly normalizer = new OkxNormalizer();
  private rateLimiter: RateLimiter | null = null;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };
  private connectTime = 0;
  private reconnectAttempt = 0;
  private reconnectTimers = new Map<WsEndpoint, ReturnType<typeof setTimeout>>();
  private messageCount = 0;
  private messageRateWindowStart = 0;
  private readonly circuitBreaker = new CircuitBreaker();
  private heartbeatTimer: ReturnType<typeof setTimeout> | undefined;
  private heartbeatTimeoutMs = DEFAULT_HEARTBEAT_TIMEOUT_MS;
  private totalErrors = 0;
  private totalRequests = 0;

  async connect(config: ExchangeConfig): Promise<void> {
    this.config = config;
    this.heartbeatTimeoutMs = config.heartbeatTimeoutMs ?? DEFAULT_HEARTBEAT_TIMEOUT_MS;
    if (config.circuitBreaker) {
      this.circuitBreaker.reset();
    }
    const rateLimitConfig = EXCHANGE_RATE_LIMITS['okx'];
    if (rateLimitConfig) {
      this.rateLimiter = new RateLimiter('okx', rateLimitConfig);
    }
    await this.circuitBreaker.execute(() => this.connectEndpoint('public'));
  }

  async disconnect(): Promise<void> {
    this.clearAllTimers();
    this.stopHeartbeat();
    for (const [endpoint, ws] of this.connections) {
      ws.onclose = null;
      ws.onerror = null;
      ws.onmessage = null;
      ws.close();
      const pingTimer = this.pingTimers.get(endpoint);
      if (pingTimer !== undefined) {
        clearInterval(pingTimer);
      }
    }
    this.connections.clear();
    this.pingTimers.clear();
    this.subscriptions.clear();
    this.statusCallbacks.clear();
    this.rateLimiter?.dispose();
    this.rateLimiter = null;
    this.circuitBreaker.reset();
    this.updateState('disconnected');
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimeSeconds = status.uptime;
    const uptimePercent = uptimeSeconds > 0
      ? Math.min(100, (uptimeSeconds / (uptimeSeconds + this.reconnectAttempt * 5)) * 100)
      : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: this.totalRequests > 0 ? this.totalErrors / this.totalRequests : 0,
      circuitBreakerState: this.circuitBreaker.state,
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('okx', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    const instId = this.toInstId(symbol);
    return this.addSubscription(symbol, 'tickers', instId, 'ticker', callback, 'public');
  }

  subscribeOrderbook(symbol: string, depth: number, callback: OrderbookCallback): AdapterSubscription {
    const instId = this.toInstId(symbol);
    const channel = depth <= 5 ? 'books5' : 'books';
    return this.addSubscription(symbol, channel, instId, 'orderbook', callback, 'public');
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    const instId = this.toInstId(symbol);
    return this.addSubscription(symbol, 'trades', instId, 'trades', callback, 'public');
  }

  subscribeOHLCV(symbol: string, timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    const instId = this.toInstId(symbol);
    const barSize = BAR_SIZE_MAP[timeframe];
    const channel = `candle${barSize}`;
    return this.addSubscription(symbol, channel, instId, 'ohlcv', callback, 'business');
  }

  async getCandles(symbol: string, timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const instId = this.toInstId(symbol);
    const bar = BAR_SIZE_MAP[timeframe];
    const allCandles: NormalizedOHLCV[] = [];

    // OKX returns max 300 candles per request and paginates with 'after' (older) param
    let afterTs = to;
    while (true) {
      const url = `${this.getRestUrl()}/api/v5/market/candles?instId=${instId}&bar=${bar}&before=${from}&after=${afterTs}&limit=300`;

      await this.rateLimiter?.acquire();
      const response = await fetch(url);
      if (!response.ok) {
        throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
      }
      const data = await response.json() as { data: OkxRestCandle[] };
      if (data.data.length === 0) break;

      const candles = data.data.map(c => this.normalizer.normalizeRestCandle(c));
      allCandles.push(...candles);

      const lastCandle = candles[candles.length - 1];
      if (!lastCandle || data.data.length < 300 || lastCandle.timestamp <= from) break;
      afterTs = lastCandle.timestamp;
    }

    return allCandles;
  }

  async getOrderbookSnapshot(symbol: string, depth: number): Promise<NormalizedOrderbook> {
    const instId = this.toInstId(symbol);
    const sz = Math.min(depth, 400);
    const url = `${this.getRestUrl()}/api/v5/market/books?instId=${instId}&sz=${sz}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      data: Array<{
        asks: [string, string, string, string][];
        bids: [string, string, string, string][];
        ts: string;
      }>;
    };

    const bookData = data.data[0];
    if (!bookData) {
      throw new Error('OKX returned empty orderbook data');
    }

    return {
      symbol: this.normalizeSymbol(instId),
      timestamp: parseNumeric(bookData.ts),
      bids: bookData.bids.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      asks: bookData.asks.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      sequenceId: 0,
      type: 'snapshot',
    };
  }

  async getRecentTrades(symbol: string, limit: number): Promise<NormalizedTrade[]> {
    const instId = this.toInstId(symbol);
    const url = `${this.getRestUrl()}/api/v5/market/trades?instId=${instId}&limit=${Math.min(limit, 500)}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      data: Array<{
        instId: string;
        tradeId: string;
        px: string;
        sz: string;
        side: 'buy' | 'sell';
        ts: string;
      }>;
    };

    return data.data.map(t => ({
      id: t.tradeId,
      timestamp: parseNumeric(t.ts),
      price: parseNumeric(t.px),
      quantity: parseNumeric(t.sz),
      side: t.side,
      buyerMaker: t.side === 'sell',
    }));
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const url = `${this.getRestUrl()}/api/v5/public/instruments?instType=SPOT`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as { data: OkxInstrumentInfo[] };

    return data.data
      .filter(s => s.state === 'live')
      .map(s => this.normalizeInstrumentInfo(s));
  }

  async getOpenInterest(symbol: string): Promise<NormalizedOpenInterest[]> {
    const instId = this.toInstId(symbol);
    const swapInstId = `${instId}-SWAP`;
    const url = `${this.getRestUrl()}/api/v5/public/open-interest?instType=SWAP&instId=${swapInstId}`;

    await this.rateLimiter?.acquire();
    this.totalRequests++;
    const response = await fetch(url);
    if (!response.ok) {
      this.totalErrors++;
      throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      data: Array<{
        instId: string;
        instType: string;
        oi: string;
        oiCcy: string;
        ts: string;
      }>;
    };

    return data.data.map((entry) => ({
      symbol: this.normalizeSymbol(instId),
      exchangeId: 'okx' as const,
      openInterest: parseNumeric(entry.oi),
      openInterestUsd: 0,
      change24h: 0,
      timestamp: parseNumeric(entry.ts),
    }));
  }

  async getFundingRate(symbol: string): Promise<NormalizedFundingRate> {
    const instId = this.toInstId(symbol);
    const swapInstId = `${instId}-SWAP`;
    const url = `${this.getRestUrl()}/api/v5/public/funding-rate?instId=${swapInstId}`;

    await this.rateLimiter?.acquire();
    this.totalRequests++;
    const response = await fetch(url);
    if (!response.ok) {
      this.totalErrors++;
      throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      data: Array<{
        instId: string;
        instType: string;
        fundingRate: string;
        nextFundingRate: string;
        fundingTime: string;
        nextFundingTime: string;
        minFundingRate: string;
        maxFundingRate: string;
        method: string;
      }>;
    };

    const entry = data.data[0];
    if (!entry) {
      throw new Error(`OKX returned no funding rate data for ${swapInstId}`);
    }

    const rate = parseNumeric(entry.fundingRate);
    const fundingTime = parseNumeric(entry.fundingTime);
    const nextFundingTime = parseNumeric(entry.nextFundingTime);
    // OKX variable intervals: derive from the gap between fundingTime and nextFundingTime
    const fundingIntervalMs = nextFundingTime > fundingTime
      ? nextFundingTime - fundingTime
      : OkxAdapter.DEFAULT_FUNDING_INTERVAL_MS;

    return {
      symbol: this.normalizeSymbol(instId),
      exchangeId: 'okx',
      rate,
      annualizedRate: rate * (365 * 24 * 3_600_000 / fundingIntervalMs),
      fundingIntervalMs,
      nextFundingTime,
      predictedRate: entry.nextFundingRate ? parseNumeric(entry.nextFundingRate) : undefined,
      timestamp: fundingTime,
    };
  }

  async getFundingRateHistory(
    symbol: string,
    params?: { startTime?: number; endTime?: number; limit?: number },
  ): Promise<NormalizedFundingRate[]> {
    const instId = this.toInstId(symbol);
    const swapInstId = `${instId}-SWAP`;
    const limit = Math.min(params?.limit ?? 100, 100);
    const results: NormalizedFundingRate[] = [];
    let after: string | undefined;

    while (true) {
      let url = `${this.getRestUrl()}/api/v5/public/funding-rate-history?instId=${swapInstId}&limit=${limit}`;
      if (params?.startTime !== undefined) url += `&before=${params.startTime}`;
      if (after !== undefined) {
        url += `&after=${after}`;
      } else if (params?.endTime !== undefined) {
        url += `&after=${params.endTime}`;
      }

      await this.rateLimiter?.acquire();
      this.totalRequests++;
      const response = await fetch(url);
      if (!response.ok) {
        this.totalErrors++;
        throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
      }
      const data = await response.json() as {
        data: Array<{
          instId: string;
          instType: string;
          fundingRate: string;
          realizedRate: string;
          fundingTime: string;
          method: string;
        }>;
      };

      if (data.data.length === 0) break;

      const normalizedSymbol = this.normalizeSymbol(instId);
      for (const entry of data.data) {
        const rate = parseNumeric(entry.fundingRate);
        results.push({
          symbol: normalizedSymbol,
          exchangeId: 'okx',
          rate,
          annualizedRate: rate * (365 * 24 * 3_600_000 / OkxAdapter.DEFAULT_FUNDING_INTERVAL_MS),
          fundingIntervalMs: OkxAdapter.DEFAULT_FUNDING_INTERVAL_MS,
          nextFundingTime: 0,
          timestamp: parseNumeric(entry.fundingTime),
        });
      }

      if (data.data.length < limit) break;
      if (params?.limit !== undefined) break;

      // OKX returns newest-first; paginate with after = oldest timestamp
      const lastEntry = data.data[data.data.length - 1];
      if (!lastEntry) break;
      after = lastEntry.fundingTime;
    }

    return results;
  }

  async getLiquidations(
    symbol: string,
    params?: { startTime?: number; limit?: number },
  ): Promise<NormalizedLiquidation[]> {
    const instId = this.toInstId(symbol);
    const swapInstId = `${instId}-SWAP`;
    const limit = Math.min(params?.limit ?? 100, 100);
    let url = `${this.getRestUrl()}/api/v5/public/liquidation-orders?instType=SWAP&instId=${swapInstId}&limit=${limit}`;
    if (params?.startTime !== undefined) url += `&before=${params.startTime}`;

    await this.rateLimiter?.acquire();
    this.totalRequests++;
    const response = await fetch(url);
    if (!response.ok) {
      this.totalErrors++;
      throw new Error(`OKX REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      data: Array<{
        details: Array<{
          side: 'buy' | 'sell';
          sz: string;
          bkPx: string;
          ts: string;
        }>;
      }>;
    };

    const normalizedSymbol = this.normalizeSymbol(instId);
    const results: NormalizedLiquidation[] = [];

    for (const entry of data.data) {
      for (const detail of entry.details) {
        const price = parseNumeric(detail.bkPx);
        const quantity = parseNumeric(detail.sz);
        results.push({
          symbol: normalizedSymbol,
          exchangeId: 'okx',
          side: detail.side === 'sell' ? 'long' : 'short',
          quantity,
          price,
          usdValue: price * quantity,
          timestamp: parseNumeric(detail.ts),
        });
      }
    }

    return results;
  }

  private normalizeInstrumentInfo(raw: OkxInstrumentInfo): NormalizedSymbol {
    return {
      symbol: `${raw.baseCcy}/${raw.quoteCcy}`,
      base: raw.baseCcy,
      quote: raw.quoteCcy,
      exchangeSymbol: raw.instId,
      exchangeId: 'okx',
      type: raw.instType === 'SPOT' ? 'spot' : 'perpetual',
      pricePrecision: this.countDecimals(raw.tickSz),
      quantityPrecision: this.countDecimals(raw.lotSz),
      minQuantity: parseNumeric(raw.minSz),
      tickSize: parseNumeric(raw.tickSz),
      active: raw.state === 'live',
    };
  }

  private countDecimals(value: string): number {
    const parts = value.split('.');
    return parts[1]?.replace(/0+$/, '').length ?? 0;
  }

  private addSubscription(
    symbol: string,
    channel: string,
    instId: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
    endpoint: WsEndpoint,
  ): AdapterSubscription {
    const id = createSubscriptionId('okx', type, symbol);
    const sub: ActiveSubscription = { id, symbol, channel, instId, type, callback, endpoint };
    this.subscriptions.set(id, sub);

    this.ensureEndpointConnection(endpoint).then(() => {
      const ws = this.connections.get(endpoint);
      if (ws?.readyState === WebSocket.OPEN) {
        this.sendSubscribe(ws, channel, instId);
      }
    }).catch(() => {
      // Connection will be retried via reconnect logic
    });

    return {
      id,
      symbol,
      type,
      dispose: () => {
        this.subscriptions.delete(id);
        const stillUsed = Array.from(this.subscriptions.values())
          .some(s => s.channel === channel && s.instId === instId);
        if (!stillUsed) {
          const ws = this.connections.get(endpoint);
          if (ws?.readyState === WebSocket.OPEN) {
            this.sendUnsubscribe(ws, channel, instId);
          }
        }
      },
    };
  }

  private async ensureEndpointConnection(endpoint: WsEndpoint): Promise<void> {
    if (this.connections.has(endpoint)) return;
    await this.connectEndpoint(endpoint);
  }

  private async connectEndpoint(endpoint: WsEndpoint): Promise<void> {
    this.updateState('connecting');
    const wsUrl = this.getWsUrl(endpoint);

    return new Promise<void>((resolve, reject) => {
      let ws: WebSocket;
      try {
        ws = new WebSocket(wsUrl);
      } catch (err) {
        this.updateState('error', err instanceof Error ? err.message : 'WebSocket creation failed');
        reject(err);
        return;
      }

      ws.onopen = () => {
        this.connections.set(endpoint, ws);
        this.connectTime = Date.now();
        this.reconnectAttempt = 0;
        this.messageRateWindowStart = Date.now();
        this.messageCount = 0;
        this.updateState('connected');
        this.startHeartbeat();

        // OKX uses text-based ping/pong
        const pingTimer = setInterval(() => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.send('ping');
          }
        }, PING_INTERVAL_MS);
        this.pingTimers.set(endpoint, pingTimer);

        // Resubscribe active channels for this endpoint
        this.resubscribeEndpoint(ws, endpoint);
        resolve();
      };

      ws.onmessage = (event: MessageEvent) => {
        this.handleMessage(event.data as string);
      };

      ws.onerror = () => {
        this.updateState('error', `WebSocket error on ${endpoint}`);
      };

      ws.onclose = () => {
        this.connections.delete(endpoint);
        const timer = this.pingTimers.get(endpoint);
        if (timer !== undefined) {
          clearInterval(timer);
          this.pingTimers.delete(endpoint);
        }
        if (this.connectionState.state !== 'disconnected') {
          this.reconnectEndpoint(endpoint);
        }
      };
    });
  }

  private handleMessage(rawData: string): void {
    this.messageCount++;
    this.resetHeartbeat();
    const now = Date.now();
    const elapsed = now - this.messageRateWindowStart;
    if (elapsed >= 10_000) {
      this.connectionState = {
        ...this.connectionState,
        messagesPerSecond: this.messageCount / (elapsed / 1000),
        lastMessageAt: now,
      };
      this.messageCount = 0;
      this.messageRateWindowStart = now;
    }

    const message = this.normalizer.parseMessage(rawData);
    if (!message) return;

    for (const sub of this.subscriptions.values()) {
      switch (sub.type) {
        case 'ticker': {
          const tick = this.normalizer.normalizeTicker(message);
          if (tick) (sub.callback as TickerCallback)(tick);
          break;
        }
        case 'trades': {
          const trade = this.normalizer.normalizeTrade(message);
          if (trade) (sub.callback as TradeCallback)(trade);
          break;
        }
        case 'ohlcv': {
          const candle = this.normalizer.normalizeOHLCV(message);
          if (candle) (sub.callback as OHLCVCallback)(candle);
          break;
        }
        case 'orderbook': {
          const book = this.normalizer.normalizeOrderbook(message);
          if (book) (sub.callback as OrderbookCallback)(book);
          break;
        }
      }
    }
  }

  private resubscribeEndpoint(ws: WebSocket, endpoint: WsEndpoint): void {
    for (const sub of this.subscriptions.values()) {
      if (sub.endpoint === endpoint) {
        this.sendSubscribe(ws, sub.channel, sub.instId);
      }
    }
  }

  private reconnectEndpoint(endpoint: WsEndpoint): void {
    if (this.connectionState.state === 'disconnected') return;
    this.stopHeartbeat();
    this.circuitBreaker.recordFailure();
    this.reconnectAttempt++;
    this.totalErrors++;
    this.updateState('reconnecting');

    const baseDelay = Math.min(1000 * Math.pow(2, this.reconnectAttempt - 1), 16_000);
    const jitter = Math.random() * baseDelay * 0.25;
    const delay = this.reconnectAttempt === 1 ? 0 : baseDelay + jitter;

    const timer = setTimeout(() => {
      this.circuitBreaker.execute(() => this.connectEndpoint(endpoint)).catch(() => {
        this.reconnectEndpoint(endpoint);
      });
    }, delay);
    this.reconnectTimers.set(endpoint, timer);
  }

  private sendSubscribe(ws: WebSocket, channel: string, instId: string): void {
    if (ws.readyState !== WebSocket.OPEN) return;
    ws.send(JSON.stringify({
      op: 'subscribe',
      args: [{ channel, instId }],
    }));
  }

  private sendUnsubscribe(ws: WebSocket, channel: string, instId: string): void {
    if (ws.readyState !== WebSocket.OPEN) return;
    ws.send(JSON.stringify({
      op: 'unsubscribe',
      args: [{ channel, instId }],
    }));
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: this.reconnectAttempt,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }

  private getWsUrl(endpoint: WsEndpoint): string {
    if (this.config?.wsUrl) return this.config.wsUrl;
    return endpoint === 'public' ? DEFAULT_PUBLIC_WS_URL : DEFAULT_BUSINESS_WS_URL;
  }

  private getRestUrl(): string {
    return this.config?.restUrl ?? DEFAULT_REST_URL;
  }

  private toInstId(symbol: string): string {
    // BTC/USDT -> BTC-USDT
    return symbol.replace('/', '-');
  }

  private normalizeSymbol(instId: string): string {
    return instId.replace('-', '/');
  }

  private startHeartbeat(): void {
    this.stopHeartbeat();
    this.heartbeatTimer = setTimeout(() => {
      this.onHeartbeatTimeout();
    }, this.heartbeatTimeoutMs);
  }

  private resetHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = setTimeout(() => {
        this.onHeartbeatTimeout();
      }, this.heartbeatTimeoutMs);
    }
  }

  private stopHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = undefined;
    }
  }

  private onHeartbeatTimeout(): void {
    this.updateState('error', 'Heartbeat timeout');
    for (const endpoint of this.connections.keys()) {
      this.reconnectEndpoint(endpoint);
    }
  }

  private clearAllTimers(): void {
    for (const timer of this.reconnectTimers.values()) {
      clearTimeout(timer);
    }
    this.reconnectTimers.clear();
  }
}
